async function testServeApp() {
  const BASE = 'http://localhost:3001';
  const res = await fetch(`${BASE}/`);
  assertEquals(res.status, 200, 'Should return 200');

  const html = await res.text();

  // Check for required structural elements
  assert(html.includes('id="map"'), 'Should contain map div');
  assert(html.includes('id="weather-canvas"'), 'Should contain weather canvas');
  assert(html.includes('id="conditions-panel"'), 'Should contain conditions panel');
  assert(html.includes('id="compass-panel"'), 'Should contain compass panel');
  assert(html.includes('id="timeline-panel"'), 'Should contain timeline panel');
  assert(html.includes('id="info-bar"'), 'Should contain info bar');

  // Check for asset references
  assert(html.includes('sailing-weather.css'), 'Should reference app CSS');
  assert(html.includes('sailing-weather.js'), 'Should reference app JS');

  // Check for Leaflet references
  assert(html.includes('leaflet'), 'Should reference Leaflet');

  // Check meta tags
  assert(html.includes('<!DOCTYPE html>'), 'Should have doctype');
  assert(html.includes('viewport'), 'Should have viewport meta');
}
